/**
 * Places the ZIP/merged bulk-download section next to the "Regrade attempts"
 * button on the quiz report overview. Falls back to a below-table placement
 * when the regrade control is not rendered (e.g. user lacks regrade cap).
 *
 * @module     local_eledia_exam2pdf/report_section_button
 * @copyright  2026 eLeDia GmbH
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define("local_eledia_exam2pdf/report_section_button",[],function(){"use strict";return{init:function(args){var section=document.getElementById(args.sectionId);if(section){var moveNextTo=document.getElementById("regradeattempts")||document.querySelector('input[name="regradeattempts"], button[name="regradeattempts"]');if(moveNextTo)return section.style.display="inline-block",section.style.margin="0 0 0 .5rem",section.style.verticalAlign="middle",void moveNextTo.insertAdjacentElement("afterend",section);section.style.margin="1rem 0 0 0"}}}});